from fastapi import FastAPI, File, UploadFile, HTTPException
from typing import Dict, Any
import pickle
import traceback

app = FastAPI()

# In a multi-tenant environment, you might want to store models in a more persistent
# and isolated way (e.g., cloud storage, dedicated model store)
# For this example, we'll use an in-memory dictionary.
# Key: model_id (derived from filename), Value: loaded model object
loaded_models: Dict[str, Any] = {}

@app.post("/models/upload")
async def upload_model(file: UploadFile = File(...)):
    """
    Upload a custom model file (pickled object) for inference.
    The model will be identified by its filename (e.g., 'mymodel.pkl').
    """
    model_id = file.filename
    if not model_id:
        raise HTTPException(status_code=400, detail="Filename missing in upload.")

    try:
        # Read the file content
        model_bytes = await file.read()

        # Deserialize the model using pickle.load
        # WARNING: Deserializing untrusted data with pickle can be dangerous.
        # Ensure proper security measures are in place in a real multi-tenant system.
        # This example assumes a controlled environment or that security is handled elsewhere.
        model = pickle.loads(model_bytes)

        # Store the loaded model
        loaded_models[model_id] = model

        return {"message": f"Model '{model_id}' uploaded and loaded successfully.", "model_id": model_id}
    except pickle.UnpicklingError as e:
        raise HTTPException(status_code=422, detail=f"Invalid pickle file: {e}")
    except Exception as e:
        # Log the full traceback for debugging in a real application
        print(f"Error loading model {model_id}: {traceback.format_exc()}")
        raise HTTPException(status_code=500, detail=f"Failed to load model: {e}")

@app.post("/models/{model_id}/predict")
async def predict(model_id: str, payload: Dict[str, Any]):
    """
    Perform inference using a previously uploaded model.
    The payload should be in a format expected by the loaded model's 'predict' method.
    """
    model = loaded_models.get(model_id)
    if model is None:
        raise HTTPException(status_code=404, detail=f"Model '{model_id}' not found. Please upload it first.")

    # Check if the model has a 'predict' method
    if not hasattr(model, 'predict') or not callable(getattr(model, 'predict')):
        raise HTTPException(status_code=400, detail=f"Model '{model_id}' does not have a callable 'predict' method.")

    try:
        # Perform inference
        # The exact input format for model.predict might vary.
        # This example assumes the payload can be directly passed or needs minimal transformation.
        # For more complex scenarios, you might need an input validation schema.
        prediction_result = model.predict([payload]) # Assuming a list of inputs for common ML models

        # Depending on the model's output, you might need to convert it to a JSON-serializable format
        # For example, if it's a numpy array, convert to list.
        if hasattr(prediction_result, 'tolist'):
            prediction_result = prediction_result.tolist()

        return {"model_id": model_id, "prediction": prediction_result}
    except Exception as e:
        print(f"Error during prediction with model {model_id}: {traceback.format_exc()}")
        raise HTTPException(status_code=500, detail=f"Prediction failed: {e}")

@app.get("/models")
async def list_models():
    """
    List all currently loaded model IDs.
    """
    return {"loaded_models": list(loaded_models.keys())}

